694			parts = append(parts, "header=true")
695			if opts.delimiter != "," {
696				parts = append(parts, fmt.Sprintf("delim='%s'", escapeSQLString(opts.delimiter)))
697			}
698			if opts.skipRows > 0 {
699				parts = append(parts, fmt.Sprintf("skip=%d", opts.skipRows))
700			}
701			return fmt.Sprintf("read_csv(%s)", strings.Join(parts, ", "))
702		case "parquet":
703			return fmt.Sprintf("read_parquet('%s')", escaped)
704		default:
705			return fmt.Sprintf("read_csv('%s', auto_detect=true)", escaped)
706		}
707	}
