203		// resolve filesystem paths without taking them as arguments. The setting
204		// is registered by the extension at LOAD time; SET runs in the same
205		// statement after LOAD via a semicolon separator.
206		connInitSQL := loadSQL
207		if cfg.ArcxStorageRoot != "" {
208			storageRoot := filepath.ToSlash(cfg.ArcxStorageRoot)
209			connInitSQL = fmt.Sprintf("%s; SET arcx.storage_root = '%s'", loadSQL, escapeSQLString(storageRoot))
210		}
211		componentLogger := logger.With().Str("component", "duckdb").Logger()
