// Converts: FROM database.measurement -> FROM read_parquet('path/**/*.parquet')
// Converts: FROM measurement -> FROM read_parquet('path/**/*.parquet')
// Converts: JOIN database.measurement -> JOIN read_parquet('path/**/*.parquet')
// Converts: JOIN measurement -> JOIN read_parquet('path/**/*.parquet')
// CTE names are extracted and excluded from conversion to avoid replacing virtual table references.
// String literals and comments are protected from regex matching.
func (h *QueryHandler) convertSQLToStoragePaths(sql string) string {
	originalSQL := sql

	// Phase 0a: Rewrite regex functions to faster string functions BEFORE masking
	// This rewrites patterns like REGEXP_REPLACE(col, 'url_pattern', '\1') to CASE expressions
	// Must happen before masking since the regex patterns contain string literals
	sql, _ = RewriteRegexToStringFuncs(sql)

	// Phase 0b: Rewrite time functions to faster epoch-based alternatives BEFORE masking
	// This must happen first because these functions contain string literals
	// that would be masked, preventing our regex from matching
	sql = rewriteTimeBucket(sql)
	sql = rewriteDateTrunc(sql)

	// Phase 0c: Optimize LIKE patterns by reordering WHERE clause predicates
	// Moves cheap operations (empty string checks) before expensive operations (LIKE scans)
	// This allows DuckDB to short-circuit rows early, reducing LIKE evaluations
	sql, _ = OptimizeLikePatterns(sql)

	// Single pass to detect features (replaces 3 separate strings.Contains calls)
	features := scanSQLFeatures(sql)

	// Phase 1: Mask string literals to prevent regex from matching inside them
	// e.g., WHERE msg = 'SELECT * FROM mydb.cpu' should not convert the string content
	sql, masks := sqlutil.MaskStringLiterals(sql, features.hasQuotes)

	// Phase 1b: Mask bare FROM inside EXTRACT/SUBSTRING/TRIM/OVERLAY so the
	// table-rewriter regex below does not treat e.g. `time` in
	// `EXTRACT(YEAR FROM time)` as a measurement.
	sql, fromMasks := sqlutil.MaskFromKeywordsInFunctionBodies(sql)

	// Phase 2: Strip SQL comments (after masking to preserve comments inside strings)
	// e.g., "-- FROM mydb.cpu" should not be converted
	sql = stripSQLComments(sql, features.hasDashComment || features.hasBlockComment)

	// Compute sqlLower once after all pre-processing mutations
	sqlLower := strings.ToLower(sql)

	// Extract CTE names to avoid converting them to storage paths
	cteNames := extractCTENames(sql)

	// Handle FROM database.table references
	sql = patternDBTable.ReplaceAllStringFunc(sql, func(match string) string {
		parts := patternDBTable.FindStringSubmatch(match)
		if len(parts) < 3 {
			return match
		}
		path := h.getStoragePath(parts[1], parts[2])
		return h.buildReadParquetExpr(path, originalSQL, "FROM")
	})

	// Handle JOIN database.table references (includes LATERAL JOIN)
	sql = patternJoinDBTable.ReplaceAllStringFunc(sql, func(match string) string {
		parts := patternJoinDBTable.FindStringSubmatch(match)
		if len(parts) < 3 {
			return match
		}
		path := h.getStoragePath(parts[1], parts[2])
		return h.buildReadParquetExpr(path, originalSQL, "JOIN")
	})

	// Handle FROM simple_table references
	sql = patternSimpleTable.ReplaceAllStringFunc(sql, func(match string) string {
		parts := patternSimpleTable.FindStringSubmatch(match)
		if len(parts) < 2 {
			return match
		}
		table := strings.ToLower(parts[1])

		// Skip if this is a CTE name - CTEs are virtual tables, not physical storage
		if cteNames[table] {
			return match
		}

		// Skip already converted read_parquet, system tables, etc.
		if shouldSkipTableConversion(table) {
			return match
		}

		// Check if followed by a dot (database.table already handled) or parenthesis (function call)
		matchLower := strings.ToLower(match)
		idx := strings.Index(sqlLower, matchLower)
		if idx >= 0 {
			afterMatch := sql[idx+len(match):]
			afterMatch = strings.TrimLeft(afterMatch, " \t")
			if len(afterMatch) > 0 && (afterMatch[0] == '.' || afterMatch[0] == '(') {
				return match
			}
		}

		path := h.getStoragePath("default", parts[1])
		return h.buildReadParquetExpr(path, originalSQL, "FROM")
	})

	// Handle JOIN simple_table references (includes LATERAL JOIN)
	sql = patternJoinSimpleTable.ReplaceAllStringFunc(sql, func(match string) string {
		parts := patternJoinSimpleTable.FindStringSubmatch(match)
		if len(parts) < 2 {
			return match
		}
		table := strings.ToLower(parts[1])

		// Skip if this is a CTE name - CTEs are virtual tables, not physical storage
		if cteNames[table] {
			return match
		}

		// Skip already converted read_parquet, system tables, etc.
		if shouldSkipTableConversion(table) {
			return match
		}

		// Check if followed by a dot or parenthesis
		matchLower := strings.ToLower(match)
		idx := strings.Index(sqlLower, matchLower)
		if idx >= 0 {
			afterMatch := sql[idx+len(match):]
			afterMatch = strings.TrimLeft(afterMatch, " \t")
			if len(afterMatch) > 0 && (afterMatch[0] == '.' || afterMatch[0] == '(') {
				return match
			}
		}

		path := h.getStoragePath("default", parts[1])
		return h.buildReadParquetExpr(path, originalSQL, "JOIN")
	})

	// Restore masked FROM keywords and string literals. Both use content-
	// addressed placeholders, so the intermediate length-changing regex
	// rewrites above are safe.
	sql = sqlutil.UnmaskFromKeywordsInFunctionBodies(sql, fromMasks)
	sql = sqlutil.UnmaskStringLiterals(sql, masks)

	return sql
}

// getStoragePath returns the storage path for a database.table
func (h *QueryHandler) getStoragePath(database, table string) string {
	return storage.GetStoragePath(h.storage, database, table)
}

// quotePath returns a safe single-quoted DuckDB string literal for use
// inside read_parquet('PATH', ...) interpolations. Single quotes inside
// the path are doubled per DuckDB's literal-escape rule. This is the
// single source of truth for path interpolation in the query layer —
// every `read_parquet('` site goes through this helper to close the
// SQL-injection vector via the x-arc-database header / measurement
// names / manifest entries (review/query-path-criticals C2).
func quotePath(path string) string {
	return "'" + sqlutil.EscapeStringLiteral(path) + "'"
}

// buildReadParquetOptions builds the read_parquet options string.
// Returns options like "union_by_name=true"

func (h *DeleteHandler) RegisterRoutes(app *fiber.App) {
	group := app.Group("/api/v1/delete")
	if h.authManager != nil {
		group.Use(auth.RequireAdmin(h.authManager))
	}
	group.Post("/", h.handleDelete)
	group.Get("/config", h.handleGetConfig)
}

// handleGetConfig returns the current delete configuration
func (h *DeleteHandler) handleGetConfig(c *fiber.Ctx) error {
	return c.JSON(DeleteConfigResponse{
		Enabled:               h.config.Enabled,
		ConfirmationThreshold: h.config.ConfirmationThreshold,
		MaxRowsPerDelete:      h.config.MaxRowsPerDelete,
		Implementation:        "rewrite-based",
		PerformanceImpact: map[string]string{
			"writes":  "zero overhead",
			"queries": "zero overhead",
			"deletes": "expensive (file rewrites)",
		},
	})
}

// handleDelete processes delete requests
func (h *DeleteHandler) handleDelete(c *fiber.Ctx) error {
	start := time.Now()

	// Check if delete operations are enabled
	if !h.config.Enabled {
		return c.Status(fiber.StatusForbidden).JSON(DeleteResponse{
			Success: false,
			Error:   "Delete operations are disabled. Set delete.enabled=true in arc.toml to enable.",
		})
	}

	// Parse request
	var req DeleteRequest
	if err := c.BodyParser(&req); err != nil {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "Invalid request body: " + err.Error(),
		})
	}

	// Validate required fields
	if req.Database == "" {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "database is required",
		})
	}
	if req.Measurement == "" {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "measurement is required",
		})
	}

	// Reject path traversal in database/measurement names — these values are
	// concatenated directly into storage prefixes and DuckDB paths.
	if strings.ContainsAny(req.Database, "/\\") || strings.Contains(req.Database, "..") {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "database name contains invalid characters",
		})
	}
	if strings.ContainsAny(req.Measurement, "/\\") || strings.Contains(req.Measurement, "..") {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "measurement name contains invalid characters",
		})
	}

	// In cluster mode, only the primary writer may execute deletes. Check before
	// findAffectedFiles to avoid running expensive DuckDB scans on reader nodes.
	if !req.DryRun && h.coordinator != nil && !h.coordinator.IsPrimaryWriter() {
		return c.Status(fiber.StatusServiceUnavailable).JSON(DeleteResponse{
			Success: false,
			Error:   fmt.Sprintf("delete rejected: node role %q is not primary writer", h.coordinator.Role()),
		})
	}

	// Validate WHERE clause
	isFullTableDelete, err := h.validateWhereClause(req.Where)
	if err != nil {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   err.Error(),
		})
	}

	// Check if confirmation is required for full table delete
	if isFullTableDelete && !req.Confirm {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "Full table delete detected (WHERE 1=1). Set confirm=true to proceed.",
		})
	}

	// Require confirmation for non-dry-run operations
	if !req.DryRun && !req.Confirm {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error:   "Confirmation required for delete operation. Set confirm=true or use dry_run=true to preview.",
		})
	}

	h.logger.Info().
		Str("database", req.Database).
		Str("measurement", req.Measurement).
		Str("where", req.Where).
		Bool("dry_run", req.DryRun).
		Msg("Processing delete request")

	// Find affected files
	ctx := c.Context()
	affected, err := h.findAffectedFiles(ctx, req.Database, req.Measurement, req.Where)
	if err != nil {
		h.logger.Error().Err(err).Msg("Failed to find affected files")
		return c.Status(fiber.StatusInternalServerError).JSON(DeleteResponse{
			Success:         false,
			Error:           "Failed to find affected files: " + err.Error(),
			ExecutionTimeMs: float64(time.Since(start).Milliseconds()),
		})
	}

	if len(affected) == 0 {
		// findAffectedFiles scanned parquet files via read_parquet — clear the cache even though
		// no rows matched, to avoid accumulating metadata for files that may later be deleted.
		h.db.ClearHTTPCache()
		freeOSMemoryThrottled()
		return c.JSON(DeleteResponse{
			Success:         true,
			DeletedCount:    0,
			AffectedFiles:   0,
			RewrittenFiles:  0,
			ExecutionTimeMs: float64(time.Since(start).Milliseconds()),
			DryRun:          req.DryRun,
			FilesProcessed:  []string{},
		})
	}

	// Calculate total rows to delete
	var totalToDelete int64
	for _, f := range affected {
		totalToDelete += f.matchCount
	}

	// Check max rows limit
	if totalToDelete > int64(h.config.MaxRowsPerDelete) {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error: fmt.Sprintf("Delete would affect %d rows, exceeding maximum of %d. "+
				"Adjust delete.max_rows_per_delete in arc.toml or refine WHERE clause.",
				totalToDelete, h.config.MaxRowsPerDelete),
		})
	}

	// Check confirmation threshold
	if totalToDelete > int64(h.config.ConfirmationThreshold) && !req.Confirm {
		return c.Status(fiber.StatusBadRequest).JSON(DeleteResponse{
			Success: false,
			Error: fmt.Sprintf("Delete would affect %d rows (threshold: %d). Set confirm=true to proceed.",
				totalToDelete, h.config.ConfirmationThreshold),
		})
	}

	h.logger.Info().
		Int("affected_files", len(affected)).
		Int64("total_rows", totalToDelete).
		Msg("Found affected files")

	// If dry run, just return stats
	if req.DryRun {
		fileNames := make([]string, len(affected))
		for i, f := range affected {
			fileNames[i] = filepath.Base(f.path)
		}

		return c.JSON(DeleteResponse{
			Success:         true,
			DeletedCount:    totalToDelete,
			AffectedFiles:   len(affected),
			RewrittenFiles:  0,
			ExecutionTimeMs: float64(time.Since(start).Milliseconds()),
			DryRun:          true,
			FilesProcessed:  fileNames,
		})
	}

	// Execute actual deletion (rewrite files)
	h.logger.Info().
		Int("file_count", len(affected)).
		Int64("rows", totalToDelete).
		Msg("Rewriting files to remove rows")

	var totalDeleted int64
	var rewrittenCount int
	processedFiles := make([]string, 0, len(affected))
	failedFiles := make([]string, 0, len(affected))

	for _, f := range affected {
		deleted, err := h.rewriteFileWithoutDeletedRows(ctx, f.path, f.relativePath, req.Where)
		if err != nil {
			h.logger.Error().Err(err).Str("file", f.path).Msg("Failed to rewrite file")
			// Manifest failures are non-transient (Raft quorum loss) — abort the
			// entire operation to avoid deleting files from storage without a
			// corresponding manifest record.
			if errors.Is(err, errManifestFailure) {
				h.db.ClearHTTPCache()
				freeOSMemoryThrottled()
				return c.Status(fiber.StatusInternalServerError).JSON(DeleteResponse{
					Success:         false,
					Error:           "Delete aborted: " + err.Error(),
					DeletedCount:    totalDeleted,
					AffectedFiles:   len(affected),
					RewrittenFiles:  rewrittenCount,
					FilesProcessed:  processedFiles,
					FailedFiles:     failedFiles,
					ExecutionTimeMs: float64(time.Since(start).Milliseconds()),
				})
			}
			failedFiles = append(failedFiles, filepath.Base(f.path))
			continue
		}
		totalDeleted += deleted

		rewrittenCount++
		processedFiles = append(processedFiles, filepath.Base(f.path))

		h.logger.Debug().
			Str("file", filepath.Base(f.path)).
			Int64("deleted", deleted).
			Msg("Processed file")
	}

	// Clear DuckDB parquet metadata/data cache and release memory back to OS.
	h.db.ClearHTTPCache()
	freeOSMemoryThrottled()

	executionTime := float64(time.Since(start).Milliseconds())

	h.logger.Info().
		Int64("deleted_count", totalDeleted).
		Int("rewritten_files", rewrittenCount).
		Int("failed_files", len(failedFiles)).
		Float64("execution_time_ms", executionTime).
		Msg("Delete operation completed")

	resp := DeleteResponse{
		Success:         len(failedFiles) == 0,
		DeletedCount:    totalDeleted,
		AffectedFiles:   len(affected),
		RewrittenFiles:  rewrittenCount,
		ExecutionTimeMs: executionTime,
		DryRun:          false,
		FilesProcessed:  processedFiles,
		FailedFiles:     failedFiles,
	}

	if len(failedFiles) > 0 {
		resp.Error = fmt.Sprintf("%d of %d files failed to process", len(failedFiles), len(affected))
		return c.Status(fiber.StatusMultiStatus).JSON(resp)
	}

	return c.JSON(resp)
}

