30	// NewLocalBackend creates a new local filesystem storage backend
31	func NewLocalBackend(basePath string, logger zerolog.Logger) (*LocalBackend, error) {
32		// Convert to absolute path to avoid issues with filepath.Rel during List operations
33		absPath, err := filepath.Abs(basePath)
34		if err != nil {
35			return nil, fmt.Errorf("failed to resolve absolute path: %w", err)
36		}
