38		// Ensure base path exists with owner-only permissions for security
39		// Files inside are created with 0600 via os.CreateTemp
40		if err := os.MkdirAll(absPath, 0700); err != nil {
41			return nil, fmt.Errorf("failed to create base path: %w", err)
42		}
43	
44		return &LocalBackend{
45			basePath: absPath,
46			logger:   logger.With().Str("component", "local-storage").Logger(),
47			dirCache: make(map[string]bool),
48		}, nil
