51	// ensureDir creates the directory if it doesn't exist, using a cache to avoid
52	// redundant os.MkdirAll calls under sustained load.
53	func (b *LocalBackend) ensureDir(dir string) error {
54		// Fast path: check if directory already exists in cache (RLock)
55		b.dirMu.RLock()
56		exists := b.dirCache[dir]
57		b.dirMu.RUnlock()
58	
59		if exists {
60			return nil
61		}
62	
63		// Slow path: create directory and update cache (Lock)
64		b.dirMu.Lock()
65		defer b.dirMu.Unlock()
66		// Double-check after acquiring write lock
67		if !b.dirCache[dir] {
68			// Use 0700 for owner-only access (security best practice)
69			if err := os.MkdirAll(dir, 0700); err != nil {
70				return fmt.Errorf("failed to create directory: %w", err)
71			}
72			b.dirCache[dir] = true
73		}
74		return nil
75	}
