80		fullPath, err := b.validatePath(path)
81		if err != nil {
82			return fmt.Errorf("invalid path: %w", err)
83		}
84	
85		dir := filepath.Dir(fullPath)
86		if err := b.ensureDir(dir); err != nil {
87			return err
88		}
89	
90		// Write to temporary file with cryptographically random name (prevents TOCTOU attacks)
91		tmpFile, err := os.CreateTemp(dir, ".arc-*.tmp")
92		if err != nil {
93			// Directory might have been deleted externally — invalidate cache and retry
94			if os.IsNotExist(err) {
95				b.dirMu.Lock()
96				delete(b.dirCache, dir)
97				b.dirMu.Unlock()
98				if err := b.ensureDir(dir); err != nil {
99					return err
100				}
101				tmpFile, err = os.CreateTemp(dir, ".arc-*.tmp")
102				if err != nil {
103					return fmt.Errorf("failed to create temp file: %w", err)
104				}
