350	// must call WriteReader (or the coordinator renames the file externally).
351	//
352	// This satisfies AppendingBackend, which the puller type-asserts before calling.
353	func (b *LocalBackend) AppendReader(ctx context.Context, path string, reader io.Reader, appendSize int64) error {
354		fullPath, err := b.validatePath(path)
355		if err != nil {
356			return fmt.Errorf("invalid path: %w", err)
357		}
358	
359		stagingPath := partPath(fullPath)
360		file, err := os.OpenFile(stagingPath, os.O_WRONLY|os.O_APPEND, 0600)
361		if err != nil {
362			metrics.Get().IncStorageErrors()
363			return fmt.Errorf("failed to open staging file for append: %w", err)
364		}
365		defer file.Close()
366	
367		written, err := io.Copy(file, reader)
368		if err != nil {
369			metrics.Get().IncStorageErrors()
370			return fmt.Errorf("failed to append file data: %w", err)
371		}
372	
373		// After appending, promote staging → final if we've received all expected bytes.
374		if written == appendSize {
375			if err := file.Close(); err != nil {
376				return fmt.Errorf("failed to close staging file: %w", err)
377			}
378			if err := os.Rename(stagingPath, fullPath); err != nil {
379				metrics.Get().IncStorageErrors()
380				return fmt.Errorf("failed to promote staging file after append: %w", err)
381			}
382		}
383	
384		metrics.Get().IncStorageWrites()
385		metrics.Get().IncStorageWriteBytes(written)
386		return nil
387	}
388	
389	// List lists all objects with the given prefix
390	func (b *LocalBackend) List(ctx context.Context, prefix string) ([]string, error) {
391		// Validate and sanitize the prefix to prevent path traversal
392		searchPath, err := b.validatePath(prefix)
393		if err != nil {
394			return nil, fmt.Errorf("invalid prefix: %w", err)
395		}
396		var results []string
397	
398		// Use filepath.Walk to recursively list files
399		err = filepath.Walk(searchPath, func(path string, info os.FileInfo, err error) error {
400			// Respect context cancellation (important for large directory trees)
401			if ctx.Err() != nil {
402				return ctx.Err()
403			}
404	
405			if err != nil {
406				// Skip directories that don't exist
407				if os.IsNotExist(err) {
408					return nil
409				}
410				return err
411			}
412	
413			// Skip directories
414			if info.IsDir() {
415				return nil
416			}
417	
418			// Skip hidden files (e.g., .DS_Store on macOS)
419			if strings.HasPrefix(info.Name(), ".") {
420				return nil
421			}
422	
423			// Get relative path from base
424			relPath, err := filepath.Rel(b.basePath, path)
425			if err != nil {
426				return err
427			}
428	
429			results = append(results, relPath)
430			return nil
431		})
432	
433		if err != nil {
434			// If the directory doesn't exist, return empty list
435			if os.IsNotExist(err) {
436				return []string{}, nil
437			}
438			return nil, fmt.Errorf("failed to list files: %w", err)
439		}
440	
441		return results, nil
442	}
443	
444	// Delete deletes the object at the specified path
445	func (b *LocalBackend) Delete(ctx context.Context, path string) error {
446		// Validate and sanitize the path to prevent path traversal
447		fullPath, err := b.validatePath(path)
448		if err != nil {
449			return fmt.Errorf("invalid path: %w", err)
450		}
451	
452		if err := os.Remove(fullPath); err != nil {
453			if os.IsNotExist(err) {
454				return nil // Already deleted, not an error
455			}
456			return fmt.Errorf("failed to delete file: %w", err)
457		}
458	
459		b.logger.Debug().
460			Str("path", path).
461			Msg("Deleted file")
462	
463		return nil
464	}
465	
466	// Exists checks if an object exists at the specified path
467	func (b *LocalBackend) Exists(ctx context.Context, path string) (bool, error) {
468		// Validate and sanitize the path to prevent path traversal
469		fullPath, err := b.validatePath(path)
470		if err != nil {
471			return false, fmt.Errorf("invalid path: %w", err)
472		}
473	
474		_, err = os.Stat(fullPath)
475		if err != nil {
476			if os.IsNotExist(err) {
477				return false, nil
478			}
479			return false, fmt.Errorf("failed to check file existence: %w", err)
480		}
481	
482		return true, nil
483	}
484	
485	// Close closes any resources held by the backend (no-op for local storage)
486	func (b *LocalBackend) Close() error {
487		return nil
488	}
489	
490	// GetFullPath returns the full filesystem path for a given storage path
491	// Useful for debugging and direct file access
492	func (b *LocalBackend) GetFullPath(path string) string {
493		// Validate and sanitize the path to prevent path traversal
494		fullPath, err := b.validatePath(path)
495		if err != nil {
496			// Return empty string for invalid paths
497			return ""
498		}
499		return fullPath
500	}
501	
502	// GetBasePath returns the base path for the local storage
503	func (b *LocalBackend) GetBasePath() string {
504		return b.basePath
505	}
506	
507	// Type returns the storage type identifier
508	func (b *LocalBackend) Type() string {
509		return "local"
510	}
511	
512	// ConfigJSON returns the configuration as JSON for subprocess recreation
513	func (b *LocalBackend) ConfigJSON() string {
514		config := map[string]string{"base_path": b.basePath}
515		data, _ := json.Marshal(config)
516		return string(data)
517	}
518	
519	// ListDirectories lists immediate subdirectories at a prefix.
520	// Implements the DirectoryLister interface.
521	func (b *LocalBackend) ListDirectories(ctx context.Context, prefix string) ([]string, error) {
522		// Validate and sanitize the prefix to prevent path traversal
523		searchPath, err := b.validatePath(prefix)
524		if err != nil {
525			return nil, fmt.Errorf("invalid prefix: %w", err)
526		}
527	
528		entries, err := os.ReadDir(searchPath)
529		if err != nil {
530			if os.IsNotExist(err) {
531				return []string{}, nil
532			}
533			return nil, fmt.Errorf("failed to read directory: %w", err)
534		}
535	
536		var dirs []string
537		for _, entry := range entries {
538			if entry.IsDir() {
539				// Skip hidden directories
540				if strings.HasPrefix(entry.Name(), ".") {
541					continue
542				}
543				dirs = append(dirs, entry.Name())
544			}
545		}
546	
547		return dirs, nil
548	}
549	
550	// DeleteBatch deletes multiple objects at the specified paths.
551	// Implements the BatchDeleter interface.
552	func (b *LocalBackend) DeleteBatch(ctx context.Context, paths []string) error {
553		var errs []error
554		for _, path := range paths {
555			if err := b.Delete(ctx, path); err != nil {
556				errs = append(errs, fmt.Errorf("%s: %w", path, err))
557				b.logger.Error().Err(err).Str("path", path).Msg("Failed to delete file in batch")
558			}
559		}
560		return errors.Join(errs...)
561	}
562	
563	// RemoveDirectory removes an empty directory.
564	// Implements the DirectoryRemover interface.
565	func (b *LocalBackend) RemoveDirectory(ctx context.Context, path string) error {
566		fullPath, err := b.validatePath(path)
567		if err != nil {
568			return fmt.Errorf("invalid path: %w", err)
569		}
570	
571		// os.Remove only removes empty directories
572		if err := os.Remove(fullPath); err != nil {
573			if os.IsNotExist(err) {
574				return nil // Already removed, not an error
575			}
576			return fmt.Errorf("failed to remove directory: %w", err)
577		}
578	
579		// Invalidate from directory cache
580		b.dirMu.Lock()
581		delete(b.dirCache, fullPath)
582		b.dirMu.Unlock()
583	
584		b.logger.Debug().
585			Str("path", path).
586			Msg("Removed directory")
587	
588		return nil
589	}
590	
591	// ListObjects lists objects with their metadata at a prefix.
592	// Implements the ObjectLister interface.
593	func (b *LocalBackend) ListObjects(ctx context.Context, prefix string) ([]ObjectInfo, error) {
594		// Validate and sanitize the prefix to prevent path traversal
595		searchPath, err := b.validatePath(prefix)
596		if err != nil {
597			return nil, fmt.Errorf("invalid prefix: %w", err)
598		}
599	
600		var results []ObjectInfo
601	
602		err = filepath.Walk(searchPath, func(path string, info os.FileInfo, err error) error {
603			// Respect context cancellation (important for large directory trees)
604			if ctx.Err() != nil {
605				return ctx.Err()
606			}
607	
608			if err != nil {
609				if os.IsNotExist(err) {
610					return nil
611				}
612				return err
613			}
614	
615			// Skip directories
616			if info.IsDir() {
617				return nil
618			}
619	
620			// Skip hidden files
621			if strings.HasPrefix(info.Name(), ".") {
622				return nil
623			}
624	
625			// Get relative path from base
626			relPath, err := filepath.Rel(b.basePath, path)
627			if err != nil {
628				return err
629			}
630	
631			results = append(results, ObjectInfo{
632				Path:         relPath,
633				Size:         info.Size(),
634				LastModified: info.ModTime(),
635			})
636			return nil
637		})
638	
639		if err != nil {
640			if os.IsNotExist(err) {
641				return []ObjectInfo{}, nil
642			}
643			return nil, fmt.Errorf("failed to list objects: %w", err)
644		}
645	
646		return results, nil
647	}
648	
649	// sanitizePath removes any potentially dangerous path components
650	func sanitizePath(path string) string {
651		// Remove leading slashes
652		path = strings.TrimPrefix(path, "/")
653	
654		// Replace .. with _ to prevent directory traversal
655		path = strings.ReplaceAll(path, "..", "_")
656	
657		// Remove any null bytes (can bypass some checks)
658		path = strings.ReplaceAll(path, "\x00", "")
659	
660		return path
661	}
662	
663	// validatePath ensures the resolved path stays within the base path (prevents path traversal)
664	func (b *LocalBackend) validatePath(path string) (string, error) {
665		// First sanitize the path
666		sanitized := sanitizePath(path)
667	
668		// Join with base path and get the absolute path
669		fullPath := filepath.Join(b.basePath, sanitized)
670		absPath, err := filepath.Abs(fullPath)
671		if err != nil {
672			return "", fmt.Errorf("failed to resolve path: %w", err)
673		}
674	
675		// Ensure the resolved path is within the base path
676		// basePath is already absolute (set in NewLocalBackend via filepath.Abs)
677		relPath, err := filepath.Rel(b.basePath, absPath)
678		if err != nil {
679			return "", fmt.Errorf("path traversal detected")
680		}
681	
682		// If the relative path starts with "..", it's outside the base path
683		if strings.HasPrefix(relPath, "..") {
684			return "", fmt.Errorf("path traversal detected: path escapes base directory")
685		}
686	
687		return absPath, nil
688	}
