	err = conn.Raw(func(driverConn any) error {
		var rawErr error
		reader, rawErr = arrowQueryOnConn(ctx, driverConn, query)
		return rawErr
	})

	if err != nil {
		conn.Close()
		return nil, nil, fmt.Errorf("arrow query failed: %w", err)
	}

	d.logger.Debug().
		Str("query", query).
		Msg("Arrow query executed")

	return reader, conn, nil
}

// ArrowQueryWithProfileContext executes a query with DuckDB profiling enabled,
// returning Arrow record batches and a QueryProfile with timing breakdown.
//
// The caller MUST close both resources when done:
//  1. reader.Release() — releases Arrow batches and closes underlying rows
//  2. conn.Close() — returns the connection to the pool
func (d *DuckDB) ArrowQueryWithProfileContext(ctx context.Context, query string) (array.RecordReader, *sql.Conn, *QueryProfile, error) {
	conn, err := d.db.Conn(ctx)
	if err != nil {
		return nil, nil, nil, fmt.Errorf("failed to acquire connection: %w", err)
	}

	// Create temp file for profiling output
	tmpFile, err := os.CreateTemp("", "duckdb_profile_*.json")
	if err != nil {
		// Fall back to non-profile Arrow query
		var reader array.RecordReader
		rawErr := conn.Raw(func(driverConn any) error {
			var err error
			reader, err = arrowQueryOnConn(ctx, driverConn, query)
			return err
		})
		if rawErr != nil {
			conn.Close()
			return nil, nil, nil, rawErr
		}
		return reader, conn, nil, nil
	}
	profilePath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(profilePath)

	// Enable profiling on this specific connection
	if _, err := conn.ExecContext(ctx, "PRAGMA enable_profiling='json'"); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to enable profiling")
	}
	if _, err := conn.ExecContext(ctx, fmt.Sprintf("PRAGMA profiling_output='%s'", profilePath)); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to set profiling output")
	}
	if _, err := conn.ExecContext(ctx, "SET custom_profiling_settings='{\"PLANNER\": \"true\", \"PLANNER_BINDING\": \"true\", \"PHYSICAL_PLANNER\": \"true\", \"OPERATOR_TIMING\": \"true\", \"OPERATOR_CARDINALITY\": \"true\"}'"); err != nil {
		d.logger.Warn().Err(err).Msg("Failed to set custom profiling settings")
	}

	// Execute query via Arrow API
	start := time.Now()
	var reader array.RecordReader
	rawErr := conn.Raw(func(driverConn any) error {
		var err error
		reader, err = arrowQueryOnConn(ctx, driverConn, query)
		return err
	})
	totalTime := time.Since(start)

	// Disable profiling
	conn.ExecContext(ctx, "PRAGMA disable_profiling")

	if rawErr != nil {
		conn.Close()
		return nil, nil, nil, fmt.Errorf("arrow query failed: %w", rawErr)
	}

	// Read profile data
	profile := &QueryProfile{
		TotalMs: float64(totalTime.Milliseconds()),
	}
	if profileData, err := os.ReadFile(profilePath); err == nil && len(profileData) > 0 {
		var profileJSON map[string]interface{}
		if err := json.Unmarshal(profileData, &profileJSON); err == nil {
			if timing, ok := profileJSON["timing"].(float64); ok {
				profile.Latency = timing * 1000
			}
			if children, ok := profileJSON["children"].([]interface{}); ok {
				for _, child := range children {
					if childMap, ok := child.(map[string]interface{}); ok {
						if name, ok := childMap["name"].(string); ok && name == "PLANNER" {
							if timing, ok := childMap["timing"].(float64); ok {
								profile.PlannerMs = timing * 1000
							}
						}
					}
				}
			}
			profile.ExecutionMs = profile.TotalMs - profile.PlannerMs
		}
	}

	return reader, conn, profile, nil
}

// ValidateSQLRequest validates an SQL query for common issues.
// Returns nil if valid, or an error with appropriate message.
// This is a shared function used by multiple query endpoints.
//
// SECURITY: The denylist regex must run on a normalised version of the
// SQL — comments stripped (so `DROP /* */ TABLE x` does not bypass the
// `\b...\b` token boundary) and string literals masked (so `SELECT
// 'DROP TABLE x'` does not false-positive). The cost is one full pass
// over the SQL; for the 10KB cap that's microseconds.
func ValidateSQLRequest(sql string) error {
	if strings.TrimSpace(sql) == "" {
		return &SQLValidationError{Message: "SQL query is required"}
	}

	if len(sql) > 10000 {
		return &SQLValidationError{Message: "SQL query exceeds maximum length (10000 characters)"}
	}

	// Normalise before denylist check: mask string literals so keywords
	// inside literals don't false-positive, then strip comments so
	// keywords interleaved with comments don't slip past token
	// boundaries (`DROP /* */ TABLE x`).
	features := scanSQLFeatures(sql)
	normalised, _ := sqlutil.MaskStringLiterals(sql, features.hasQuotes)
	normalised = stripSQLComments(normalised, features.hasDashComment || features.hasBlockComment)

	if dangerousSQLPattern.MatchString(normalised) {
		return &SQLValidationError{Message: "Dangerous SQL operation not allowed"}
	}

	// SECURITY: reject user SQL that calls read_parquet() directly.
	// Only Arc's transformation layer (convertSQLToStoragePaths and
	// related) emits read_parquet — any occurrence in user input is a
	// RBAC bypass vector: a user scoped to db1.m1 could read
	// /data/db2/secrets/**/*.parquet by routing around the table-name
	// → path mapping that RBAC depends on. See review/query-path-
	// criticals C3.
	if userSQLReadParquetPattern.MatchString(normalised) {
		return &SQLValidationError{Message: "Direct read_parquet() calls are not allowed in user SQL"}
	}

	// SECURITY: reject user SQL that calls arcx's table functions
	// directly. arc_partition_agg(db, m, unit) takes raw database and
	// measurement strings and globs the filesystem; without this block,
	// a user authenticated for db1 could call
	// arc_partition_agg('db2', 'mem', 'hour') and learn row counts in
	// db2. Same RBAC bypass shape as read_parquet — only Arc's query
	// rewriter, which has the user's identity, may emit calls to it.
	if userSQLArcPartitionAggPattern.MatchString(normalised) {
		return &SQLValidationError{Message: "Direct arc_partition_agg() calls are not allowed in user SQL"}
	}

	return nil
}

// userSQLReadParquetPattern matches `read_parquet(` as a function call
// (case-insensitive, allowing whitespace before the open paren). Only
// runs against masked/comment-stripped SQL so a literal containing
// "read_parquet" or a comment is fine.
var userSQLReadParquetPattern = regexp.MustCompile(`(?i)\bread_parquet\s*\(`)

// userSQLArcPartitionAggPattern matches `arc_partition_agg(` as a
// function call. arcx exposes filesystem-anchored row counts; user SQL
// must route through Arc's rewriter so RBAC stays load-bearing.
var userSQLArcPartitionAggPattern = regexp.MustCompile(`(?i)\barc_partition_agg\s*\(`)

// getTransformedSQL returns the transformed SQL with caching.
// If headerDB is non-empty, uses the optimized path with that database for all tables.
// Returns the transformed SQL and whether it was a cache hit.
func (h *QueryHandler) getTransformedSQL(sql string, headerDB string) (string, bool) {
	// Fast path: queries already using read_parquet don't need transformation
	sqlLower := strings.ToLower(sql)
	if strings.Contains(sqlLower, "read_parquet") {
		return sql, true // Return as "hit" since no work needed
	}

	// Fast path: queries without FROM or JOIN don't need table transformation
	// (e.g., SELECT 1+1, SELECT NOW(), SHOW commands handled elsewhere)
	if !strings.Contains(sqlLower, "from") && !strings.Contains(sqlLower, "join") {
		return sql, true
	}

	// Build cache key - include header database if provided
	cacheKey := sql
	if headerDB != "" {
		cacheKey = headerDB + ":" + sql
	}

	// Check cache
	if transformed, ok := h.queryCache.Get(cacheKey); ok {
		return transformed, true
	}

	// Transform using appropriate method
	var transformed string
	if headerDB != "" {
		transformed = h.convertSQLToStoragePathsWithHeaderDB(sql, headerDB)
	} else {
		transformed = h.convertSQLToStoragePaths(sql)
	}

	h.queryCache.Set(cacheKey, transformed)
	return transformed, false
}

