	`|\bSET\b` +
	`|\bRESET\b` +
	`|\bLOAD\b` +
	`|\bINSTALL\b` +
	// CALL matches the bare keyword. The previous "\s+\w+" form was
	// bypassable via `CALL(proc)` (no whitespace before paren) — gemini
	// round 1.
	`|\bCALL\b` +
	`)`)

